// ─── Helper de tradução ──────────────────────────────────────────────────────
export function t(lang, key, vars) {
  const dict = STRINGS[lang] || STRINGS.pt;
  let s = (key in dict) ? dict[key] : (key in STRINGS.pt ? STRINGS.pt[key] : key);
  if (vars) for (const k in vars) s = s.split("{" + k + "}").join(String(vars[k]));
  return s;
}

// ─── Persistência + contexto (painel) ────────────────────────────────────────
export function getStoredLang() {
  try { const l = localStorage.getItem("rh_lang"); return LANGS.some(x => x.code === l) ? l : "pt"; }
  catch { return "pt"; }
}
export function storeLang(l) { try { localStorage.setItem("rh_lang", l); } catch {} }

export const LangContext = createContext({ lang: "pt", setLang: () => {}, t: (k, v) => t("pt", k, v) });
export const useLang = () => useContext(LangContext);
